import { createWorkspace, teardownWorkspace } from "@tigrisdata/agent-kit";
import { S3Client, PutObjectCommand } from "@aws-sdk/client-s3";
import { readFileSync, writeFileSync, unlinkSync, existsSync } from "fs";

const STATE_FILE = "/home/user/pool/pool-state.json";
const TIGRIS_ENDPOINT = "REDACTED";

interface WorkspaceEntry {
  name: string;
  bucket: string;
  credentials: {
    accessKeyId: string;
    secretAccessKey: string;
  };
}

interface PoolState {
  workspaces: WorkspaceEntry[];
}

function readState(): PoolState {
  if (!existsSync(STATE_FILE)) {
    throw new Error(`pool-state.json not found at ${STATE_FILE}`);
  }
  return JSON.parse(readFileSync(STATE_FILE, "utf-8")) as PoolState;
}

export async function provisionPool(n: number): Promise<void> {
  const names: string[] = [];
  for (let i = 1; i <= n; i++) {
    names.push(`pool-${n}-${i}`);
  }

  const results = await Promise.all(
    names.map((name) =>
      createWorkspace(name, {
        ttl: { days: 1 },
        credentials: { role: "Editor" },
      })
    )
  );

  const entries: WorkspaceEntry[] = [];
  for (let i = 0; i < results.length; i++) {
    const result = results[i];
    if (result.error) {
      throw new Error(
        `Failed to provision workspace ${names[i]}: ${result.error.message}`
      );
    }
    const data = result.data!;
    if (!data.credentials) {
      throw new Error(
        `No credentials returned for workspace ${names[i]}`
      );
    }
    entries.push({
      name: names[i],
      bucket: data.bucket,
      credentials: {
        accessKeyId: data.credentials.accessKeyId,
        secretAccessKey: data.credentials.secretAccessKey,
      },
    });
  }

  const state: PoolState = { workspaces: entries };
  writeFileSync(STATE_FILE, JSON.stringify(state, null, 2), "utf-8");
  console.log(`Provisioned ${n} workspaces and wrote pool-state.json`);
}

export async function assignTask(
  agentIndex: number,
  text: string
): Promise<void> {
  const state = readState();
  const entry = state.workspaces[agentIndex - 1];
  if (!entry) {
    throw new Error(
      `Agent index ${agentIndex} is out of range (pool size: ${state.workspaces.length})`
    );
  }

  const client = new S3Client({
    endpoint: TIGRIS_ENDPOINT,
    region: "REDACTED",
    credentials: {
      accessKeyId: entry.credentials.accessKeyId,
      secretAccessKey: entry.credentials.secretAccessKey,
    },
    forcePathStyle: false,
  });

  await client.send(
    new PutObjectCommand({
      Bucket: entry.bucket,
      Key: "task.txt",
      Body: text,
    })
  );

  console.log(
    `Uploaded task.txt to bucket ${entry.bucket} for agent ${agentIndex}`
  );
}

export function status(): void {
  const state = readState();
  console.log(`pool size: ${state.workspaces.length}`);
  for (const ws of state.workspaces) {
    console.log(ws.bucket);
  }
}

export async function teardownPool(): Promise<void> {
  const state = readState();

  const results = await Promise.allSettled(
    state.workspaces.map((ws) =>
      teardownWorkspace({ bucket: ws.bucket, credentials: ws.credentials })
    )
  );

  // Always remove state file after settling
  if (existsSync(STATE_FILE)) {
    unlinkSync(STATE_FILE);
  }

  const failures: string[] = [];
  for (let i = 0; i < results.length; i++) {
    const r = results[i];
    if (r.status === "rejected") {
      failures.push(
        `Workspace ${state.workspaces[i].name}: ${r.reason}`
      );
    } else if (r.status === "fulfilled" && r.value.error) {
      failures.push(
        `Workspace ${state.workspaces[i].name}: ${r.value.error.message}`
      );
    }
  }

  if (failures.length > 0) {
    throw new Error(`Teardown had failures:\n${failures.join("\n")}`);
  }

  console.log(
    `Torn down ${state.workspaces.length} workspaces and removed pool-state.json`
  );
}

import { provisionPool, assignTask, status, teardownPool } from "./manager.js";

const args = process.argv.slice(2);
const subcommand = args[0];

async function main() {
  switch (subcommand) {
    case "provision": {
      const n = parseInt(args[1], 10);
      if (isNaN(n) || n < 1) {
        console.error("Usage: cli.ts provision <N> (N must be a positive integer)");
        process.exitCode = 1;
        return;
      }
      await provisionPool(n);
      break;
    }

    case "assign-task": {
      const agentIndex = parseInt(args[1], 10);
      const text = args[2];
      if (isNaN(agentIndex) || agentIndex < 1) {
        console.error("Usage: cli.ts assign-task <agent-index> <text>");
        process.exitCode = 1;
        return;
      }
      if (text === undefined) {
        console.error("Usage: cli.ts assign-task <agent-index> <text>");
        process.exitCode = 1;
        return;
      }
      await assignTask(agentIndex, text);
      break;
    }

    case "status": {
      status();
      break;
    }

    case "teardown": {
      await teardownPool();
      break;
    }

    default: {
      console.error(
        `Unknown subcommand: ${subcommand ?? "(none)"}\n` +
        "Usage: cli.ts <subcommand> [args...]\n" +
        "Subcommands: provision <N> | assign-task <agent-index> <text> | status | teardown"
      );
      process.exitCode = 1;
      return;
    }
  }
}

main().catch((err) => {
  console.error(err instanceof Error ? err.message : String(err));
  process.exitCode = 1;
});
